function dbSetPlayerMultiactive($player_id = -1, $value = 1) {
    if (! $value)
        $value = 0;
    else
        $value = 1;
    $sql = "UPDATE `player` SET `player_is_multiactive` = '$value' WHERE `player_zombie` = 0 and `player_eliminated` = 0";
